// Parse incoming chat message
const body = $json["body"] || {};

const chatData = {
  messageId: body.message_id || '',
  conversationId: body.conversation_id || '',
  userId: body.user_id || '',
  userName: body.user_name || '',
  message: body.message || '',
  timestamp: body.timestamp || new Date().toISOString(),
  platform: body.platform || 'website',
  metadata: body.metadata || {}
};

return [{ json: chatData }];

// Determine customer info and message intent
const customers = $json;
const message = ($json["message"] || '').toLowerCase();
const userId = $json["userId"];

let customer = null;
if (customers && customers.length > 0) {
  customer = customers[0];
}

// Analyze message for intent
const intents = [];
if (message.includes('price') || message.includes('cost') || message.includes('value')) {
  intents.push('price_inquiry');
}
if (message.includes('visit') || message.contains('tour') || message.contains('see')) {
  intents.push('viewing_request');
}
if (message.includes('agent') || message.contains('representative')) {
  intents.push('agent_request');
}
if (message.includes('mortgage') || message.contains('financing') || message.contains('loan')) {
  intents.push('financing_question');
}
if (message.includes('buy') || message.contains('purchase') || message.contains('offer')) {
  intents.push('purchase_intent');
}
if (message.includes('sell') || message.contains('listing') || message.contains('market')) {
  intents.push('selling_inquiry');
}

// Default to general inquiry if no specific intent
if (intents.length === 0) {
  intents.push('general_inquiry');
}

return [{ json: {
  customerId: customer ? customer.id : null,
  customerName: customer ? `${customer.first_name} ${customer.last_name}` : 'Unknown User',
  customerEmail: customer ? customer.email : null,
  customerPhone: customer ? customer.phone : null,
  originalMessage: $json["message"],
  detectedIntents: intents,
  conversationId: $json["conversationId"],
  messageId: $json["messageId"],
  needsFollowUp: intents.includes('viewing_request') || intents.includes('purchase_intent'),
  priority: intents.includes('purchase_intent') ? 'high' : (intents.includes('viewing_request') ? 'medium' : 'low'),
  suggestedResponse: generateSuggestedResponse(intents, customer),
  timestamp: new Date().toISOString()
} }];

function generateSuggestedResponse(intents, customer) {
  const name = customer ? customer.first_name : 'there';

  if (intents.includes('price_inquiry')) {
    return `Hi ${name}! I'd be happy to help you with pricing information. Could you tell me which property you're interested in?`;
  }
  if (intents.includes('viewing_request')) {
    return `Hi ${name}! I can help you schedule a viewing. What date and time works best for you?`;
  }
  if (intents.includes('agent_request')) {
    return `Hi ${name}! Would you like to be connected with a specific agent, or shall I have our team lead assist you?`;
  }
  if (intents.includes('financing_question')) {
    return `Hi ${name}! Our financing specialists can help answer your mortgage questions. Would you like me to connect you with one?`;
  }
  if (intents.includes('purchase_intent')) {
    return `Hi ${name}! It sounds like you're ready to make an offer. Let's discuss the details and next steps.`;
  }
  if (intents.includes('selling_inquiry')) {
    return `Hi ${name}! I'd be glad to help you with selling your property. Can you tell me more about what you're looking to sell?`;
  }
  return `Hi ${name}! Thanks for reaching out. How can I assist you with your real estate needs today?`;
}
